import{_ as e,o as a,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"3.人机改-肢体","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/人机改/3.人机改-肢体.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/人机改/3.人机改-肢体.md"}'),s={name:"4.资源分区/2.改造与功法/改造/4.综合类/人机改/3.人机改-肢体.md"};function _(o,b,d,l,i,c){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"_3-人机改-肢体",tabindex:"-1"},[t("3.人机改-肢体 "),r("a",{class:"header-anchor",href:"#_3-人机改-肢体","aria-label":'Permalink to "3.人机改-肢体"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023元旦版")])])],-1),n('<h1 id="_3-人机改-肢体-1" tabindex="-1">3.人机改-肢体 <a class="header-anchor" href="#_3-人机改-肢体-1" aria-label="Permalink to &quot;3.人机改-肢体&quot;">​</a></h1><p>肢体</p><p>“大力”臂部人工肌肉<br> 1000<br> 廉价的人工肌肉，而且只在臂部植入，会导致植入者的身体看起来非常不协调。<br> 植入者的负重能力将视同体积额外提升6点，并获得2点力量检定上的器械加值。</p><p>“飞毛腿”腿部人工肌肉<br> 1000<br> 廉价的人工肌肉，而且只会在大腿植入，会导致植入者的身体看起来非常不协调。<br> 植入者的腿部天生武器将能够造成严重伤害，并提升15点基础移速。</p><p>携物槽<br> 1000<br> 用于在身体中装备武器的改造，可以起到隐蔽和突然袭击的作用。<br> 可以在上肢任意位置镶嵌一个携物槽，在其中最多能携带一把体积不超过3的武器，取出这件武器时使用一个迅捷动作。<br> 可以额外再支付1000分购买高级版，在这件武器取出的那个回合进行的攻击还视为具有D级措手不及。</p><p>万用数据线<br> 500<br> 从手部延伸而出，可以自由伸缩回收的数据线，可以用来接入网络或者传输数据。<br> 数据线能够接入的所有网络，都视为可以正常上网，这是一个无支线信息来源的效果。</p><p>“蛛丝”抓取型数据线<br> C+1200<br> 你的手腕外侧被安装上了特殊的数据线，比起发射，更需要你使用敏捷/力量-运动-专业：投掷-专业：弹道学将它们“甩”出去，被视为伤害0L的投掷武器。<br> 数据线头具有【回力】特性，如果在一次攻击后没能成功收回，可以使用一个移动动作将数据线卷回自己的手腕。<br> 可以选择让数据线头接触到目标后抓取目标，将攻击出目转换为纠缠点数。也可以选择用数据线的插头击打目标特定部位，将攻击出目转换为肢体妨碍点数。<br> 数据线头造成的攻击均为钝击</p><p>“足轻”臂刃植入<br> D+500<br> 前提：具有携物槽<br> 在手臂上植入一把上好的长刀，可以起到突然袭击的作用。<br> 获得储放于手臂中的【机械长刀】。<br> 机械长刀<br> 科技本质<br> 体积3<br> 这是一把充满科技气息的长刀，刀身轻薄微曲，单刃，仔细看可以看到刀背上的电路装置。</p><p>【特殊武装】刀柄结构类似自行车，带有扳机。扣下扳机会像手枪一样顺着刀刃指向的方向发射子弹。<br> 使用枪部分进行攻击时，会带给对手C级的措手不及效果。<br> 刀 伤害6L 破甲2<br> 枪 伤害6L 高速5 短点射 装弹数11</p><p>【能量体运用】使用时按下像是自行车手刹的东西，便会将装载进刀柄的能量模块发挥效用，使刀刃和子弹附带对应效果，一开始并不会自己装载模块，但在经过适应改装后，可以通过支付2点电力来充当能量体。</p><p>增压指尖<br> 1000<br> 在指尖或拳眼上加装增压模块，可以有效的攻击敌人，造成伤害。<br> 使用天生武器进行肉搏攻击将会自动造成严重伤害，并提升1点攻击上的附加成功。</p><p>手部能量炮<br> B+2400/一双<br> 你手臂的钢铁骨髓被替换为能量压缩器，掌根处延伸出炮口，使用时需要伸直手臂，尽可能站稳，手掌与手臂呈90度。<br> 【能量炮】<br> 能量炮被视为伤害19L、射程40M、体积4额外附带2威猛的【能量武器】，因此在接受此改造后你的手臂可能会看起来有点长。<br> 使用能量炮攻击会消耗3点电力，使用敏捷-射击-专业：能量炮-辅助专业：弹道学发射出带有9加骰的能量光束，并附带出目1/4的晕眩点数，攻击距离不足15M的目标时额外附带2威猛。<br> 每次使用能量炮攻击会为肢体带来2点【热量】<br> 【蓄力射击】<br> 额外花费一个标准动作进行蓄力，炮口处因为能量高度压缩能够看到某种颜色的能量反应，下次射击会发射出经过强压缩的能量光束，对40M以内直线范围的所有地方个体造成伤害 ，并获得【超级贯通】。<br> 蓄力可以被带有针对手部的肢体妨碍的攻击打断。<br> 蓄力后使用能量炮攻击会为肢体带来3点【热量】</p><p>》》》》》》》》》<br> 肢体推进器系列<br> 特殊的，此改造会占据左右两边各一个改造槽，在上肢和下肢分别仅能进行一次相关改造。</p><p>【手臂推进】<br> D+500<br> 对上肢进行改造，在手腕和关节处安装小型推进器，在使用拳掌或者近战武器等武技相关检定增加等同于耐力附加成功+1的器械加值，攻击时会推进器会瞬间启动，为本次攻击增加【6威猛】，同时为上肢带来1点热量。</p><p>【热情拥抱】<br> D+500<br> 对上肢进行改造，在手臂外侧安装推进器，在使用擒抱时无视体积带来的优势与劣势，擒抱检定增加等同于耐力附加成功+1的器械加值。在擒抱期间推进器会通过大功率运作，喷射出滚烫的气体，额外获得2点偏斜防御，同时擒抱期间每回合为上肢带来1点热量。</p><p>【腿部推进】<br> D+500<br> 对下肢进行改造，在小腿后侧安装推进器，移动时通过推进器助力，使移速增加15米，获得4先攻，在使用腿部天生武器进行的攻击检定增加等同于耐力附加成功+1的器械加值，同时为下肢带来1点热量。</p><p>【导弹推进器】<br> C+1000<br> 对下肢进行改造，将膝盖以下改为导弹用推进器，由于推进器火力问题，接受改造后仅获得普通的飞行能力，但是在经历过一场影片后，如果在影片中使用过飞行能力，那么会因为熟练度提升使飞行能力提升一级（普通-良好-完美），最高到完美。<br> 在空中对地面单位进行冲锋攻击时，有效距离取最大值计算，在冲锋的移动行为结束后，即使对方离开了攻击范围也可以按照脱离攻击范围一般进行冲锋攻击，并且获得【贯穿】。<br> 为维持飞行，飞行的每回合需要消耗1电力，同时每回合为下肢带来3热量。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',19)])])}const m=e(s,[["render",_]]);export{f as __pageData,m as default};
